refsection.latex:
\begin{eqnarray}
\mbox{min} & f\left(x\right) & \\
\mbox{subject to} & g_{lower} \leq g\left(x\right) \leq g_{upper} & \\
\mbox{and} & x_{i}^{\mbox{min}}\leq x_{i}\leq x_{i}^{\mbox{max}} & i=1,\cdots,n
\end{eqnarray}

refsection.programlisting:

// Definition of the optimization problem

// The objective function
function y=f(x,x_new)
    y=4*x(1) - x(2)^2 - 12;
end

function y=df(x,x_new)
    y(1) = 4;
    y(2) = -2*x(2);
end

// The constraints
function y=g(x,x_new)
    y(1) = - 10*x(1) + x(1)^2 - 10*x(2) + x(2)^2 + 34;
    y(2) = 20 - x(1)^2 - x(2)^2;
end

function y=dg(x,x_new)
    y(1) = -10 + 2*x(1)
    y(2) = -10 + 2*x(2);
    y(3) = -2*x(1);
    y(4) = -2*x(2);
end

// The sparsity structure of the constraints
sparse_dg = [1 1; 1 2; 2 1; 2 2];

// The Hessian of the Lagrangian (lower triangle non-zero terms)
function y = dh(x,x_new,obj_weight,lambda,lambda_new)
    y(1) = lambda(1)*2 - lambda(2)*2;
    y(2) = -obj_weight*2 + lambda(1)*2 - lambda(2)*2;
end

// The sparsity structure of the lower triangle of the Hessian of the Lagrangian
sparse_dh = [1 1;2 2];

upper = [15;15];
lower = [-15;-15];
x0    = [-12;-12]; // Feasible starting point

var_lin_type    = [1 1]; // Non-Linear
constr_lin_type = [1 1]; // Non-Linear
constr_rhs      = [0 0];
constr_lhs      = [-10000 0];

////////////////////////////////////////////////////////////////////////

params = struct();
params.hessian_approximation = "exact";

[x_sol, f_sol, extra] = ipopt(x0, f, df, g, dg, sparse_dg, dh, sparse_dh, var_lin_type, constr_lin_type, ...
                              constr_rhs, constr_lhs, lower, upper, [], params);
disp(x_sol)
disp(extra)


function f=residual(x,_t,_y)
    z=x(1)*cos(x(2)*_t+x(3)).*exp(x(4)*_t.^2);
    r=z-_y;
    f=sum(r.*r);    
endfunction

// a combined objective and gradient of objective function
// with user parameters _t and _y
function [f,df] = costf(x, new_x, _t, _y)
    f = residual(x);
    if argn(1) == 2 then
        n=length(x)    
        df=zeros(n,1);
        xi=x;
        //gradient with complex step
        dx = 1e-100;
        for k=1:n
            xi(k)=complex(x(k),dx);
            df(k) = imag(residual(xi,_t,_y))/dx;
            xi(k)=x(k);
        end
    end
endfunction

// a combined constraints and constraints Jacobian function
function [g,dg] = constr(x,new_x)
    g = norm(x)^2-6;
    if argn(1) == 2 then
        dg =  2*x;
    end    
endfunction

// intermediate callback function with user parameters _t and _y
function out = intcb(param,_t,_y)
    if isfield(param,"x")
        x = param.x;
        z=x(1)*cos(x(2)*_t+x(3)).*exp(x(4)*_t.^2);
        drawlater
        clf
        plot(_t,z,_t,_y,'o')
        gca().data_bounds(3:4)=[-1.5,1.5];
        legend model data
        drawnow
    end
    out = %t;
endfunction

// generate the data to be fitted
t=linspace(-10,10,100);
y=cos(2*t+1).*exp(-0.1*t.^2);
y=y+rand(y,'normal')/10;

// specify the optimization problem using a structure
problem = struct();
problem.x0 = rand(4,1);
problem.f = list(costf,t,y);
problem.g = constr;
problem.constr_rhs = 0;
problem.constr_lhs = -%inf;
problem.x_lower = [0 0 0 -%inf];
problem.x_upper = [%inf %inf %inf 0];
problem.int_cb =  list(intcb,t,y);

[x,f,extra] = ipopt(problem);

disp(x,extra)


function [f, g, H] = rosenfgh(x,xnew)
    f = 100*(x(2) - x(1)^2)^2 + (1-x(1))^2;
    if argn(1) > 1 // g required
        g = [-400*(x(2)-x(1)^2)*x(1)-2*(1-x(1));
            200*(x(2)-x(1)^2)];
        if argn(1) > 2// H required
            H = [1200*x(1)^2-400*x(2)+2, -400*x(1);
                -400*x(1), 200];  
        end
    end
end

problem = struct();
problem.f = rosenfgh;
problem.x0 = [0;0];
problem.hessian_approximation = "exact";

x=ipopt(problem);


f_C = ['#include <math.h>'
        'int f_C(double * x, double * f, int n_size_x, double x_new)'
        '{'
        '  f[0] = 5*pow(x[0],2) - 3*pow(x[1],2);'
        '  return 1;'
        '}'];

df_C = ['#include <math.h>'
        'int df_C(double * x, double * df, int n_size_x, double x_new)'
        '{'
        '  df[0] = 10*x[0];'
        '  df[1] = -6*x[1];'
        '  return 1;'
        '}'];

g_C = ['#include <math.h>'
       'int g_C(double * x, int n_size_x, double * g, int n_size_g, double x_new)'
       '{'
       '  g[0] = -x[0];'
       '  g[1] = -x[1];'
       '  return 1;'
       '}'];

dg_C = ['#include <math.h>'
        '#include <stdio.h>'
        'int dg_C(double * x, int n_size_x, double new_x, int n_size_g, double * values)'
        '{'
        '  values[0] = -1;'
        '  values[1] = -1;'
        '  return 1;'
        '}'];

current_dir = pwd();
cd TMPDIR;
mputl(f_C, TMPDIR+'/ipopt_demo_f_C.c');
mputl(df_C,TMPDIR+'/ipopt_demo_df_C.c');
mputl(g_C, TMPDIR+'/ipopt_demo_g_C.c');
mputl(dg_C,TMPDIR+'/ipopt_demo_dg_C.c');

// compile the C code
printf('Compilation of the f_C function\n');
f_C_handle  = ilib_for_link('f_C', 'ipopt_demo_f_C.c', [],'c');
printf('Compilation of the df_C function\n');
df_C_handle = ilib_for_link('df_C','ipopt_demo_df_C.c',[],'c');
printf('Compilation of the g_C function\n');
g_C_handle  = ilib_for_link('g_C', 'ipopt_demo_g_C.c', [],'c');
printf('Compilation of the dg_C function\n');
dg_C_handle = ilib_for_link('dg_C','ipopt_demo_dg_C.c',[],'c');

// incremental linking
link(f_C_handle, 'f_C', 'c');
link(df_C_handle,'df_C','c');
link(g_C_handle, 'g_C', 'c');
link(dg_C_handle,'dg_C','c');

cd(current_dir);

upper = [ 4  4];
lower = [-4 -4];
x0    = [1 1];

var_lin_type    = [1 1]; // Non-Linear
constr_lin_type = [0 0]; // Linear
constr_rhs      = [0 0];
constr_lhs      = -[%inf %inf];

sparse_dg = [1 1; 2 2];

[x_sol, f_sol, extra] = ipopt(x0, 'f_C', 'df_C', 'g_C', 'dg_C', sparse_dg, [], [], ...
                              var_lin_type, [], constr_rhs, constr_lhs, lower, upper, [])
